#!/usr/bin/perl
use strict;
use warnings;
use File::Slurp;
use File::Spec;
use JSON;
use Data::Dumper;

my $config_dir = $ENV{'PLUGIN_CONFIG_DIR'} || './plugins';
my $plugin_registry = {};
my $plugin_hooks = {};

sub load_plugin_config {
    my ($config_file) = @_;
    
    unless (-f $config_file) {
        warn "Config file not found: $config_file\n";
        return undef;
    }
    
    my $content = read_file($config_file);
    my $config;
    
    eval {
        $config = decode_json($content);
    };
    
    if ($@) {
        warn "Failed to parse JSON config: $@\n";
        return undef;
    }
    
    return $config;
}

sub register_plugin {
    my ($plugin_name, $plugin_code, $metadata) = @_;
    
    $metadata ||= {};
    
    my $plugin_sub;
    eval {
        $plugin_sub = eval $plugin_code;
    };
    
    if ($@) {
        warn "Failed to compile plugin '$plugin_name': $@\n";
        return 0;
    }
    
    $plugin_registry->{$plugin_name} = {
        code => $plugin_sub,
        raw_code => $plugin_code,
        metadata => $metadata,
        loaded_at => time(),
    };
    
    if ($metadata->{hooks}) {
        foreach my $hook (@{$metadata->{hooks}}) {
            push @{$plugin_hooks->{$hook}}, $plugin_name;
        }
    }
    
    print "Plugin '$plugin_name' registered successfully\n";
    return 1;
}

sub execute_plugin {
    my ($plugin_name, @args) = @_;
    
    unless (exists $plugin_registry->{$plugin_name}) {
        warn "Plugin '$plugin_name' not found\n";
        return undef;
    }
    
    my $plugin = $plugin_registry->{$plugin_name};
    my $result;
    
    eval {
        if (ref($plugin->{code}) eq 'CODE') {
            $result = $plugin->{code}->(@args);
        } else {
            eval $plugin->{raw_code};
            $result = $@ ? undef : 1;
        }
    };
    
    if ($@) {
        warn "Plugin '$plugin_name' execution failed: $@\n";
        return undef;
    }
    
    return $result;
}

sub execute_hook {
    my ($hook_name, @args) = @_;
    
    my @results;
    
    if (exists $plugin_hooks->{$hook_name}) {
        foreach my $plugin_name (@{$plugin_hooks->{$hook_name}}) {
            my $result = execute_plugin($plugin_name, @args);
            push @results, $result if defined $result;
        }
    }
    
    return @results;
}

sub load_all_plugins {
    my ($dir) = @_;
    $dir ||= $config_dir;
    
    unless (-d $dir) {
        warn "Plugin directory not found: $dir\n";
        return 0;
    }
    
    opendir(my $dh, $dir) or die "Cannot open directory: $!\n";
    my @files = grep { /\.(json|conf)$/ } readdir($dh);
    closedir($dh);
    
    foreach my $file (@files) {
        my $full_path = File::Spec->catfile($dir, $file);
        my $config = load_plugin_config($full_path);
        
        next unless $config;
        
        if ($config->{enabled}) {
            my $plugin_name = $config->{name} || $file;
            my $plugin_code = $config->{code};
            
            if ($config->{code_file}) {
                my $code_file = File::Spec->catfile($dir, $config->{code_file});
                if (-f $code_file) {
                    $plugin_code = read_file($code_file);
                }
            }
            
            if ($plugin_code) {
                register_plugin($plugin_name, $plugin_code, $config->{metadata});
            }
        }
    }
    
    return 1;
}

sub reload_plugin {
    my ($plugin_name) = @_;
    
    delete $plugin_registry->{$plugin_name};
    
    foreach my $hook (keys %$plugin_hooks) {
        $plugin_hooks->{$hook} = [grep { $_ ne $plugin_name } @{$plugin_hooks->{$hook}}];
    }
    
    load_all_plugins();
}

sub list_plugins {
    my @plugins;
    
    foreach my $name (sort keys %$plugin_registry) {
        push @plugins, {
            name => $name,
            loaded_at => $plugin_registry->{$name}->{loaded_at},
            metadata => $plugin_registry->{$name}->{metadata},
        };
    }
    
    return @plugins;
}

